code.C++:
#include <bits/stdc++.h>
using namespace std;

int main() {
    // your code goes here
    int year;

    cin >> year;

    // Check if the year is a leap year
    if ((year % 4 == 0 && year % 100 != 0) || (year % 400 == 0)) {
        cout <<"Leap year"<< endl;
    } else {
        cout <<"Not a leap year" << endl;
    }

    return 0;
}

